import { ACCT_META, ALT_PACKS, LOAN_META, MAIN_PACKS, ML, MS, PC, PORTFOLIOS, TICKER_META, _gaLang, mLabel } from "../constants/meta";
import { useTh } from "../contexts/theme";
import { gaDownloadCompleteReport, gaEmailCompleteReport } from "../services/supabase";
import { GOLD, mCARD, mIIN, mINP, mTD, mTDR, mTH, mTHR, stripLeadEmoji } from "../styles/theme";
import { RATIOS_META, actB, bE, cardMoInt, effectiveMin, fmt, fmtD, fmtDate, fmtS, gid, liquidA, ratColor, sumB, sumMin, sumN, toM, totalA, totalL, totalMoInt } from "../utils/finance";
import { Donut, Radar5, RadialGauge, RankedHBars, SmoothAreaLine, Treemap, Waterfall } from "./charts";
import { BillsSection, CustomAssetsSection, DebtSection, IncomeSection, NotesSection, SavingsSection } from "./clientSections";
import { PremiumLockNote, PremiumUpgrade, usePremiumGate } from "./premium";
import { BSolid, Btn, Field, InfoTip, MaskedNumInp, Modal, PTag, Pill, Row2, SBadge, SC, SaveBar, YearInp } from "./primitives";
