  const INP=mINP(th);
  const chartData=[];for(let y=1;y<=years;y++){const n2=y*12;const v=monthly>0?(monthly*((Math.pow(1+r,n2)-1)/r)):0;chartData.push({year:"Yr "+y,value:Math.round(v),contrib:Math.round(monthly*n2)});}
